-- SQL Schema for Student Evaluation System\n\n-- Table for Users\nCREATE TABLE users (\n    user_id INT PRIMARY KEY AUTO_INCREMENT,\n    username VARCHAR(50) NOT NULL UNIQUE,\n    password VARCHAR(255) NOT NULL,\n    role ENUM('student', 'teacher', 'admin') NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Table for Teachers\nCREATE TABLE teachers (\n    teacher_id INT PRIMARY KEY AUTO_INCREMENT,\n    user_id INT NOT NULL,\n    subject VARCHAR(100),\n    FOREIGN KEY (user_id) REFERENCES users(user_id) ON DELETE CASCADE\n);\n\n-- Table for Students\nCREATE TABLE students (\n    student_id INT PRIMARY KEY AUTO_INCREMENT,\n    user_id INT NOT NULL,\n    enrollment_date DATE,\n    FOREIGN KEY (user_id) REFERENCES users(user_id) ON DELETE CASCADE\n);\n\n-- Table for Courses\nCREATE TABLE courses (\n    course_id INT PRIMARY KEY AUTO_INCREMENT,\n    course_name VARCHAR(100) NOT NULL,\n    teacher_id INT NOT NULL,\n    FOREIGN KEY (teacher_id) REFERENCES teachers(teacher_id) ON DELETE CASCADE\n);\n\n-- Table for Evaluation Questions\nCREATE TABLE evaluation_questions (\n    question_id INT PRIMARY KEY AUTO_INCREMENT,\n    question_text TEXT NOT NULL\n);\n\n-- Table for Evaluations\nCREATE TABLE evaluations (\n    evaluation_id INT PRIMARY KEY AUTO_INCREMENT,\n    course_id INT NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (course_id) REFERENCES courses(course_id) ON DELETE CASCADE\n);\n\n-- Table for Evaluation Responses\nCREATE TABLE evaluation_responses (\n    response_id INT PRIMARY KEY AUTO_INCREMENT,\n    evaluation_id INT NOT NULL,\n    student_id INT NOT NULL,\n    question_id INT NOT NULL,\n    response TEXT,\n    FOREIGN KEY (evaluation_id) REFERENCES evaluations(evaluation_id) ON DELETE CASCADE,\n    FOREIGN KEY (student_id) REFERENCES students(student_id) ON DELETE CASCADE,\n    FOREIGN KEY (question_id) REFERENCES evaluation_questions(question_id) ON DELETE CASCADE\n);\n\n-- Table for Reports\nCREATE TABLE reports (\n    report_id INT PRIMARY KEY AUTO_INCREMENT,\n    evaluation_id INT NOT NULL,\n    generated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (evaluation_id) REFERENCES evaluations(evaluation_id) ON DELETE CASCADE\n);\n\n-- Table for Audit Logs\nCREATE TABLE audit_logs (\n    log_id INT PRIMARY KEY AUTO_INCREMENT,\n    action VARCHAR(255),\n    user_id INT,\n    timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (user_id) REFERENCES users(user_id) ON DELETE SET NULL\n);\n\n-- Indexes\nCREATE INDEX idx_user_role ON users(role);\nCREATE INDEX idx_teacher_subject ON teachers(subject);